class UnionFind {
    constructor(size) {
        this.parent = Array.from({ length: size }, (_, i) => i);
        this.rank = new Array(size).fill(0);
    }

    find(u) {
        if (this.parent[u] !== u) {
            this.parent[u] = this.find(this.parent[u]);
        }
        return this.parent[u];
    }

    union(u, v) {
        const rootU = this.find(u);
        const rootV = this.find(v);
        if (rootU === rootV) return false;

        if (this.rank[rootU] > this.rank[rootV]) {
            this.parent[rootV] = rootU;
        } else if (this.rank[rootU] < this.rank[rootV]) {
            this.parent[rootU] = rootV;
        } else {
            this.parent[rootV] = rootU;
            this.rank[rootU]++;
        }
        return true;
    }
}

function solve(n, edges, k) {
    const mustEdges = [];
    const optionalEdges = [];
    for (const [u, v, s, must] of edges) {
        if (must === 1) {
            mustEdges.push([u, v, s]);
        } else {
            optionalEdges.push([u, v, s]);
        }
    }

    const uf = new UnionFind(n);
    let components = n;

    // First, process all must edges
    for (const [u, v, s] of mustEdges) {
        if (uf.union(u, v)) {
            components--;
        }
    }

    if (components === 1) {
        // All nodes are connected by must edges, find min strength among must edges
        let minStrength = Infinity;
        for (const [u, v, s] of mustEdges) {
            minStrength = Math.min(minStrength, s);
        }
        return minStrength;
    }

    // Sort optional edges in descending order of strength (to maximize min strength)
    optionalEdges.sort((a, b) => b[2] - a[2]);

    // Process optional edges without upgrades first
    const tempUf = new UnionFind(n);
    for (const [u, v, s] of mustEdges) {
        tempUf.union(u, v);
    }

    const selectedEdges = [];
    for (const [u, v, s] of optionalEdges) {
        if (tempUf.union(u, v)) {
            selectedEdges.push([u, v, s]);
        }
    }

    if (tempUf.find(0) !== tempUf.find(n - 1)) {
        // Check if all nodes are connected
        let allConnected = true;
        const root = tempUf.find(0);
        for (let i = 1; i < n; i++) {
            if (tempUf.find(i) !== root) {
                allConnected = false;
                break;
            }
        }
        if (!allConnected) {
            return -1;
        }
    }

    // Now, process with upgrades
    const upgradedEdges = optionalEdges.map(([u, v, s]) => [u, v, s * 2]);
    const allEdges = [...mustEdges, ...upgradedEdges, ...optionalEdges];
    allEdges.sort((a, b) => b[2] - a[2]);

    const ufFinal = new UnionFind(n);
    let usedUpgrades = 0;
    let minStability = Infinity;
    let selectedCount = 0;

    for (const [u, v, s] of allEdges) {
        if (ufFinal.union(u, v)) {
            minStability = Math.min(minStability, s);
            selectedCount++;
            if (s > optionalEdges.find(([u1, v1, s1]) => u1 === u && v1 === v && s1 * 2 === s)?.[2]) {
                usedUpgrades++;
            }
        }
        if (selectedCount === n - 1) break;
    }

    if (selectedCount < n - 1) {
        return -1;
    }

    // Now, we need to maximize minStability by choosing which edges to upgrade
    // Binary search for the maximum possible min strength
    let left = 1;
    let right = 1e5 * 2;
    let answer = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const ufCheck = new UnionFind(n);
        let componentsCheck = n;
        let upgradesUsed = 0;

        // Process must edges first
        for (const [u, v, s] of mustEdges) {
            if (s >= mid) {
                if (ufCheck.union(u, v)) {
                    componentsCheck--;
                }
            }
        }

        // Process optional edges with possible upgrades
        for (const [u, v, s] of optionalEdges) {
            if (componentsCheck === 1) break;
            const upgradedS = s * 2;
            if (upgradedS >= mid && upgradesUsed < k) {
                if (ufCheck.union(u, v)) {
                    componentsCheck--;
                    upgradesUsed++;
                }
            } else if (s >= mid) {
                if (ufCheck.union(u, v)) {
                    componentsCheck--;
                }
            }
        }

        if (componentsCheck === 1) {
            answer = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return answer;
}

